import static org.mockito.Mockito.*;

import java.io.IOException;
import java.lang.reflect.Field;

import org.apache.commons.csv.CSVParser;
import org.apache.commons.csv.Lexer;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVParserTest {

    private CSVParser parser;
    private Lexer lexerMock;

    @BeforeEach
    void setUp() throws Exception {
        // Create a CSVParser instance with a dummy Reader and CSVFormat (mock or null as needed)
        parser = new CSVParser(new java.io.StringReader(""), null);

        // Create a mock Lexer
        lexerMock = mock(Lexer.class);

        // Use reflection to set the private lexer field to the mock
        Field lexerField = CSVParser.class.getDeclaredField("lexer");
        lexerField.setAccessible(true);
        lexerField.set(parser, lexerMock);
    }

    @Test
    void close_lexerNotNull_callsLexerClose() throws IOException {
        // Call the close method
        parser.close();

        // Verify lexer.close() was called once
        verify(lexerMock, times(1)).close();
    }

    @Test
    void close_lexerNull_noExceptionThrown() throws Exception {
        // Set lexer field to null via reflection
        Field lexerField = CSVParser.class.getDeclaredField("lexer");
        lexerField.setAccessible(true);
        lexerField.set(parser, null);

        // Call close and assert no exception thrown
        parser.close();
    }
}
